"use client";

import * as React from "react";
import { 
  ChevronDown, 
  ArrowRight, 
  Sparkles, 
  Layout, 
  ShieldCheck, 
  Globe 
} from "lucide-react";
import { cn } from "@/lib/utils";
import { Button } from "@/components/ui/button";
import { Logo } from "@/components/logo";

const MARQUEE_ITEMS = [
  { icon: Sparkles, text: "Freddy UI Pro is now available with 50+ premium blocks" },
  { icon: Layout, text: "New 'Announcement' category just dropped! Check it out" },
  { icon: ShieldCheck, text: "Built with Shadcn UI, Tailwind CSS and Framer Motion" },
  { icon: Globe, text: "Trusted by 5,000+ developers worldwide" },
];

export const MarqueeHeader = () => {
  return (
    <header className="w-full border-b border-border bg-background">
      {/* Marquee Bar */}
      <div className="relative flex h-9 items-center overflow-hidden border-b border-border bg-muted/30">
        <div className="flex animate-marquee whitespace-nowrap py-2 [--duration:40s] [--gap:2rem]">
          {[...Array(4)].map((_, i) => (
            <div key={i} className="flex shrink-0 items-center gap-8 px-4">
              {MARQUEE_ITEMS.map((item, idx) => (
                <div key={idx} className="flex items-center gap-2 text-[12px] font-medium text-muted-foreground transition-colors hover:text-foreground">
                  <item.icon className="h-3.5 w-3.5 text-primary/60" />
                  <span>{item.text}</span>
                  <ArrowRight className="h-3 w-3 opacity-30 group-hover:block hidden" />
                </div>
              ))}
            </div>
          ))}
        </div>

        {/* Fades for smooth entry/exit */}
        <div className="pointer-events-none absolute inset-y-0 left-0 w-20 bg-linear-to-r from-background to-transparent z-10" />
        <div className="pointer-events-none absolute inset-y-0 right-0 w-20 bg-linear-to-l from-background to-transparent z-10" />
      </div>

      {/* Main Navigation */}
      <nav className="container flex h-16 items-center justify-between px-4 sm:px-6">
        {/* Logo */}
        <div className="flex items-center gap-2 shrink-0">
          <Logo className="h-7" />
        </div>

        {/* Centered Desktop Menu */}
        <div className="hidden items-center gap-8 md:flex">
          <MenuLink label="Components" hasDropdown />
          <MenuLink label="Blocks" hasDropdown />
          <MenuLink label="Showcase" />
          <MenuLink label="Templates" hasDropdown />
          <MenuLink label="Docs" />
        </div>

        {/* Right Actions */}
        <div className="flex items-center gap-4 shrink-0">
          <button 
            type="button"
            className="hidden text-sm font-semibold text-muted-foreground transition-colors hover:text-foreground sm:block"
          >
            Log In
          </button>
          <Button 
            className="h-10 rounded-xl px-6 font-bold shadow-sm transition-all hover:scale-[1.02] active:scale-[0.98]"
          >
            Get Freddy UI
          </Button>
        </div>
      </nav>
    </header>
  );
};

interface MenuLinkProps {
  label: string;
  hasDropdown?: boolean;
}

const MenuLink = ({ label, hasDropdown }: MenuLinkProps) => {
  return (
    <button
      type="button"
      className="group flex items-center gap-1 text-[15px] font-medium text-muted-foreground transition-colors hover:text-foreground"
    >
      {label}
      {hasDropdown && (
        <ChevronDown className="h-4 w-4 transition-transform group-hover:rotate-180" />
      )}
    </button>
  );
};
